--
-- Name: expire_old_memberships(); Type: PROCEDURE; Schema: public; Owner: postgres
--

CREATE PROCEDURE public.expire_old_memberships()
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_mem_record    RECORD;
    v_expired_count INT := 0;
    v_already_count INT := 0;

    -- Explicit cursor for all memberships
    cur_memberships CURSOR FOR
        SELECT m.membership_id,
               m.visitor_id,
               m.expiry_date,
               m.is_active,
               v.first_name || ' ' || v.last_name AS visitor_name
        FROM memberships m
        JOIN visitors v ON m.visitor_id = v.visitor_id
        ORDER BY m.membership_id;

BEGIN
    OPEN cur_memberships;
    LOOP
        FETCH cur_memberships INTO v_mem_record;
        EXIT WHEN NOT FOUND;

        -- Branch: check if membership is expired
        IF v_mem_record.expiry_date < CURRENT_DATE AND v_mem_record.is_active = TRUE THEN

            -- Mark membership as inactive (DML)
            UPDATE memberships
            SET is_active = FALSE
            WHERE membership_id = v_mem_record.membership_id;

            -- Deduct loyalty points from visitor (DML)
            UPDATE visitors
            SET loyalty_points = GREATEST(0, loyalty_points - 50)
            WHERE visitor_id = v_mem_record.visitor_id;

            v_expired_count := v_expired_count + 1;

            RAISE NOTICE 'Membership % for visitor % has been expired.',
                v_mem_record.membership_id,
                v_mem_record.visitor_name;

        ELSIF v_mem_record.is_active = FALSE THEN
            v_already_count := v_already_count + 1;
        END IF;

    END LOOP;
    CLOSE cur_memberships;

    RAISE NOTICE 'Expiry process complete. Newly expired: %, Already inactive: %.',
        v_expired_count, v_already_count;

EXCEPTION
    WHEN OTHERS THEN
        RAISE EXCEPTION 'Error in expire_old_memberships: %', SQLERRM;
END;
$$;


ALTER PROCEDURE public.expire_old_memberships() OWNER TO postgres;

--
-- Name: get_employee_report(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_employee_report() RETURNS refcursor
    LANGUAGE plpgsql
    AS $$
DECLARE
    ref_cur         REFCURSOR := 'employee_report_cursor';
    v_emp_record    RECORD;
    v_trans_count   INT;
    v_total_revenue NUMERIC;
    v_performance   TEXT;

    -- Explicit cursor for all employees
    cur_employees CURSOR FOR
        SELECT e.employee_id,
               e.first_name,
               e.last_name,
               e.hire_date,
               e.bonus_amount,
               COALESCE(m.first_name || ' ' || m.last_name, 'No Manager') AS manager_name
        FROM employees e
        LEFT JOIN manager m ON e.manager_id = m.manager_id
        ORDER BY e.employee_id;

BEGIN
    -- Create temp table to hold report data
    DROP TABLE IF EXISTS temp_employee_report;
    CREATE TEMP TABLE temp_employee_report (
        employee_id        INT,
        employee_name      TEXT,
        hire_date          DATE,
        manager_name       TEXT,
        total_transactions INT,
        total_revenue      NUMERIC,
        bonus_amount       NUMERIC,
        performance        TEXT
    );

    -- Loop through all employees
    OPEN cur_employees;
    LOOP
        FETCH cur_employees INTO v_emp_record;
        EXIT WHEN NOT FOUND;

        -- Count transactions per employee (implicit cursor)
        SELECT COUNT(*), COALESCE(SUM(total_amount), 0)
        INTO v_trans_count, v_total_revenue
        FROM transactions
        WHERE employee_id = v_emp_record.employee_id;

        -- Branch: classify performance
        IF v_trans_count >= 100 THEN
            v_performance := 'Excellent';
        ELSIF v_trans_count >= 50 THEN
            v_performance := 'Good';
        ELSIF v_trans_count >= 10 THEN
            v_performance := 'Average';
        ELSE
            v_performance := 'Low';
        END IF;

        -- Insert into temp table (DML)
            v_emp_record.employee_id,
            v_emp_record.first_name || ' ' || v_emp_record.last_name,
            v_emp_record.hire_date,
            v_emp_record.manager_name,
            v_trans_count,
            v_total_revenue,
            v_emp_record.bonus_amount,
            v_performance
        );

    END LOOP;
    CLOSE cur_employees;

    -- Open ref cursor on temp table and return it
    OPEN ref_cur FOR
        SELECT * FROM temp_employee_report
        ORDER BY total_revenue DESC;

    RETURN ref_cur;

EXCEPTION
    WHEN OTHERS THEN
        RAISE EXCEPTION 'Error in get_employee_report: %', SQLERRM;
END;
$$;


ALTER FUNCTION public.get_employee_report() OWNER TO postgres;

--
-- Name: get_visitor_summary(integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_visitor_summary(p_visitor_id integer) RETURNS TABLE(visitor_name text, total_transactions bigint, total_spent numeric, loyalty_points integer, membership_status text)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_record        visitors%ROWTYPE;
    v_trans_count   BIGINT := 0;
    v_total_spent   NUMERIC := 0;
    v_loyalty       INT := 0;
    v_membership    TEXT := 'No Membership';

    -- Explicit cursor for transactions
    cur_transactions CURSOR FOR
        SELECT total_amount
        FROM transactions
        WHERE visitor_id = p_visitor_id;

    v_trans_row RECORD;
BEGIN
    -- Get visitor record using implicit cursor
    BEGIN
        SELECT * INTO STRICT v_record
        FROM visitors
        WHERE visitor_id = p_visitor_id;
    EXCEPTION
        WHEN NO_DATA_FOUND THEN
            RAISE EXCEPTION 'Visitor with ID % not found', p_visitor_id;
    END;

    -- Loop through transactions using explicit cursor
    OPEN cur_transactions;
    LOOP
        FETCH cur_transactions INTO v_trans_row;
        EXIT WHEN NOT FOUND;

        v_trans_count := v_trans_count + 1;
        v_total_spent := v_total_spent + v_trans_row.total_amount;
    END LOOP;
    CLOSE cur_transactions;

    -- Calculate loyalty points (10 per transaction)
    v_loyalty := v_trans_count * 10;

    -- Update loyalty points in database (DML)
    UPDATE visitors
    SET loyalty_points     = v_loyalty,
        last_activity_date = CURRENT_DATE
    WHERE visitor_id = p_visitor_id;

    -- Check membership status using branches
    IF EXISTS (
        SELECT 1 FROM memberships
        WHERE visitor_id = p_visitor_id
          AND is_active = TRUE
          AND expiry_date >= CURRENT_DATE
    ) THEN
        v_membership := 'Active Member';
    ELSIF EXISTS (
        SELECT 1 FROM memberships
        WHERE visitor_id = p_visitor_id
    ) THEN
        v_membership := 'Expired Member';
    ELSE
        v_membership := 'No Membership';
    END IF;

    -- Return result row
    RETURN QUERY SELECT
        v_record.first_name || ' ' || v_record.last_name,
        v_trans_count,
        v_total_spent,
        v_loyalty,
        v_membership;

EXCEPTION
    WHEN OTHERS THEN
        RAISE EXCEPTION 'Error in get_visitor_summary: %', SQLERRM;
END;
$$;


ALTER FUNCTION public.get_visitor_summary(p_visitor_id integer) OWNER TO postgres;

--
-- Name: trg_fn_log_price_change(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.trg_fn_log_price_change() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    -- Branch: only log if price actually changed
    IF OLD.base_price <> NEW.base_price THEN

        -- Insert log record (DML)
        VALUES (NEW.ticket_id, OLD.base_price, NEW.base_price, NOW());

        RAISE NOTICE 'Price change logged for ticket %. Old: %, New: %',
            NEW.ticket_id,
            OLD.base_price,
            NEW.base_price;
    ELSE
        RAISE NOTICE 'No price change detected for ticket %. Skipping log.',
            NEW.ticket_id;
    END IF;

    RETURN NEW;

EXCEPTION
    WHEN OTHERS THEN
        RAISE EXCEPTION 'Error in trg_log_price_change: %', SQLERRM;
END;
$$;


ALTER FUNCTION public.trg_fn_log_price_change() OWNER TO postgres;

--
-- Name: trg_fn_update_loyalty_points(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.trg_fn_update_loyalty_points() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_current_points INT;
BEGIN
    -- Get current loyalty points (implicit cursor)
    SELECT loyalty_points INTO v_current_points
    FROM visitors
    WHERE visitor_id = NEW.visitor_id;

    -- Branch: handle case where visitor doesn't exist
    IF NOT FOUND THEN
        RAISE EXCEPTION 'Visitor % not found when updating loyalty points', NEW.visitor_id;
    END IF;

    -- Add 10 loyalty points and update last activity (DML)
    UPDATE visitors
    SET loyalty_points     = COALESCE(v_current_points, 0) + 10,
        last_activity_date = CURRENT_DATE
    WHERE visitor_id = NEW.visitor_id;

    RAISE NOTICE 'Loyalty points updated for visitor %. New total: %',
        NEW.visitor_id,
        COALESCE(v_current_points, 0) + 10;

    RETURN NEW;

EXCEPTION
    WHEN OTHERS THEN
        RAISE EXCEPTION 'Error in trg_update_loyalty_points: %', SQLERRM;
END;
$$;


ALTER FUNCTION public.trg_fn_update_loyalty_points() OWNER TO postgres;

--
-- Name: update_employee_bonuses(); Type: PROCEDURE; Schema: public; Owner: postgres
--

CREATE PROCEDURE public.update_employee_bonuses()
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_emp_record    RECORD;
    v_revenue       NUMERIC;
    v_bonus         NUMERIC;
    v_updated_count INT := 0;

    -- Explicit cursor for all employees
    cur_emp CURSOR FOR
        SELECT employee_id, first_name, last_name
        FROM employees
        ORDER BY employee_id;

BEGIN
    OPEN cur_emp;
    LOOP
        FETCH cur_emp INTO v_emp_record;
        EXIT WHEN NOT FOUND;

        -- Calculate total revenue for this employee (implicit cursor)
        SELECT COALESCE(SUM(total_amount), 0)
        INTO v_revenue
        FROM transactions
        WHERE employee_id = v_emp_record.employee_id;

        -- Branch: determine bonus based on revenue tiers
        IF v_revenue >= 100000 THEN
            v_bonus := v_revenue * 0.05;  -- 5% bonus
        ELSIF v_revenue >= 50000 THEN
            v_bonus := v_revenue * 0.03;  -- 3% bonus
        ELSIF v_revenue >= 10000 THEN
            v_bonus := v_revenue * 0.01;  -- 1% bonus
        ELSE
            v_bonus := 0;
        END IF;

        -- Update bonus in database (DML)
        UPDATE employees
        SET bonus_amount = v_bonus
        WHERE employee_id = v_emp_record.employee_id;

        v_updated_count := v_updated_count + 1;

        -- Print notice for high performers
        IF v_bonus > 0 THEN
            RAISE NOTICE 'Employee % % received bonus: %',
                v_emp_record.first_name,
                v_emp_record.last_name,
                v_bonus;
        END IF;

    END LOOP;
    CLOSE cur_emp;

    RAISE NOTICE 'Bonus update complete. % employees processed.', v_updated_count;

EXCEPTION
    WHEN OTHERS THEN
        RAISE EXCEPTION 'Error in update_employee_bonuses: %', SQLERRM;
END;
$$;


ALTER PROCEDURE public.update_employee_bonuses() OWNER TO postgres;

