--

CREATE VIEW public.view_employee_manager AS
 SELECT e.employee_id,
    e.first_name AS employee_first_name,
    e.last_name AS employee_last_name,
    e.hire_date,
    m.manager_id,
    m.first_name AS manager_first_name,
    m.last_name AS manager_last_name,
    m.seniority_level,
    p.project_name,
    p.status AS project_status,
    p.budget
   FROM ((public.employees e
     JOIN public.manager m ON ((e.manager_id = m.manager_id)))
     JOIN public.project p ON ((p.manager_id = m.manager_id)));


