--
-- Name: view_project_transactions; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.view_project_transactions AS
 SELECT p.project_id,
    p.project_name,
    p.status AS project_status,
    p.budget,
    (((m.first_name)::text || ' '::text) || (m.last_name)::text) AS manager_name,
    m.seniority_level,
    e.employee_id,
    e.first_name AS employee_first_name,
    e.last_name AS employee_last_name,
    t.transaction_id,
    t.transaction_date,
    t.total_amount,
    t.payment_method,
    v.first_name AS visitor_first_name,
    v.last_name AS visitor_last_name
   FROM ((((public.project p
     JOIN public.manager m ON ((m.manager_id = p.manager_id)))
     JOIN public.employees e ON ((e.manager_id = m.manager_id)))
     JOIN public.transactions t ON ((t.employee_id = e.employee_id)))
     JOIN public.visitors v ON ((v.visitor_id = t.visitor_id)));


ALTER VIEW public.view_project_transactions OWNER TO postgres;

